const hotelRooms = {};
DB.hotels.forEach(h => hotelRooms[h] = []);
DB.price.forEach(p => {
  if(!hotelRooms[p.hotel]) hotelRooms[p.hotel] = [];
  if(!hotelRooms[p.hotel].includes(p.room)) hotelRooms[p.hotel].push(p.room);
});

function fmt(n){ return n.toLocaleString('ja-JP'); }

// Always show room types in a consistent order: シングル, ツイン, トリプル first,
// then any other room names (e.g. ANA's コンフォート/プレミアム variants) keep their
// original relative order from the data.
const ROOM_ORDER = ['シングル', 'ツイン', 'トリプル'];
function roomSortKey(roomName){
  for(let i = 0; i < ROOM_ORDER.length; i++){
    if(roomName.includes(ROOM_ORDER[i])) return i;
  }
  return ROOM_ORDER.length;
}
function sortRooms(rooms){
  return rooms
    .map((room, idx) => ({ room, idx }))
    .sort((a, b) => (roomSortKey(a.room) - roomSortKey(b.room)) || (a.idx - b.idx))
    .map(x => x.room);
}

const ANA_HOTEL = DB.fit_ana.hotel;
const PRINCE_HOTEL = DB.fit_prince.hotel;
const SOLARIA_HOTEL = DB.fit_solaria.hotel;

// FIT pricing at these hotels can be less reliable than the group rate, so
// show a caution note whenever the guest count falls into their FIT range.
const FIT_UNCERTAIN_HOTELS = {
  '登別万世閣': 14,
  '洞爺万世閣': 14,
  [DB.fit_ana.hotel]: DB.fit_ana.threshold
};

function findRowIn(list, hotel, room, dateStr){
  return list.find(p => p.hotel === hotel && p.room === room && p.start <= dateStr && p.end >= dateStr) || null;
}

function findPriceRow(hotel, room, dateStr){
  return findRowIn(DB.price, hotel, room, dateStr);
}

function getAccommodationTax(hotel, afterTax){
  const rows = DB.tax.filter(r => r.hotel === hotel);
  for(const r of rows){
    const max = (r.max === null || r.max === undefined) ? Infinity : r.max;
    if(afterTax >= r.min && afterTax < max) return r.tax;
  }
  return 0;
}

function getBathTax(hotel){
  const v = DB.bath[hotel];
  return (v === null || v === undefined) ? 0 : v;
}

function weekdayIndexUTC(dateStr){
  const [y,m,d] = dateStr.split('-').map(Number);
  return new Date(Date.UTC(y, m-1, d)).getUTCDay();
}

function isClosedRow(row){
  return typeof row.base === 'string' || typeof row.fri === 'string' || typeof row.sat === 'string';
}

function surchargeFor(row, dow){
  if(dow === 5) return row.fri;
  if(dow === 6) return row.sat;
  return 0;
}

/**
 * Works out the room base/surcharge to use and the FIT surtax (diff) to add,
 * given the hotel's own FIT/団体(group) rules.
 * Returns { ok:true, row, diff } or { ok:false, reason }
 */
function resolveQuote(hotel, room, dateStr, guests){
  if(hotel === SOLARIA_HOTEL && guests <= DB.fit_solaria.threshold){
    const row = findRowIn(DB.fit_solaria.price, hotel, room, dateStr);
    if(!row) return { ok:false, reason:'no_data' };
    if(isClosedRow(row)) return { ok:false, reason:'closed' };
    return { ok:true, row, diff:0 };
  }

  const groupRow = findPriceRow(hotel, room, dateStr);
  if(!groupRow) return { ok:false, reason:'no_data' };
  if(isClosedRow(groupRow)) return { ok:false, reason:'closed' };

  if(hotel === ANA_HOTEL){
    if(guests > DB.fit_ana.threshold) return { ok:true, row:groupRow, diff:0 };
    const tier = DB.fit_ana.tiers.find(t => guests >= t.min && guests <= t.max);
    const diff = tier ? tier.amount : 0;
    return { ok:true, row:groupRow, diff };
  }

  if(hotel === PRINCE_HOTEL){
    if(guests > DB.fit_prince.threshold) return { ok:true, row:groupRow, diff:0 };
    const special = dateStr >= DB.fit_prince.special_start && dateStr <= DB.fit_prince.special_end;
    const bracket = DB.fit_prince.rooms[room];
    const diff = bracket ? (special ? bracket.special : bracket.normal) : 0;
    return { ok:true, row:groupRow, diff };
  }

  const entry = DB.fit_simple[hotel];
  if(entry && entry.threshold > 0 && guests <= entry.threshold){
    return { ok:true, row:groupRow, diff:entry.amount };
  }
  return { ok:true, row:groupRow, diff:0 };
}

function computeFinalPrice(hotel, dateStr, quote){
  const { row } = quote;
  if(row.base === 0 && row.fri === 0 && row.sat === 0) return null;
  const dow = weekdayIndexUTC(dateStr);
  const surcharge = surchargeFor(row, dow);

  const preTax = row.base + surcharge + quote.diff;
  const afterTax = Math.round(preTax * 1.1);
  const accTax = getAccommodationTax(hotel, afterTax);
  const bathTax = getBathTax(hotel);
  const totalBeforeRound = afterTax + accTax + bathTax;
  return Math.ceil(totalBeforeRound / 100) * 100;
}

let minD = null, maxD = null;
DB.price.forEach(p => {
  if(minD === null || p.start < minD) minD = p.start;
  if(maxD === null || p.end > maxD) maxD = p.end;
});

